import{_ as o,o as e,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const n=JSON.parse('{"title":"1974年 · 危机中的机会","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-year/1974年.md","filePath":"05_quotes/by-year/1974年.md"}'),u={name:"05_quotes/by-year/1974年.md"};function l(q,t,c,h,s,p){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="_1974年-·-危机中的机会" tabindex="-1">1974年 · 危机中的机会 <a class="header-anchor" href="#_1974年-·-危机中的机会" aria-label="Permalink to &quot;1974年 · 危机中的机会&quot;">​</a></h1><blockquote><p>&quot;在别人恐惧时贪婪。这句话所有人都知道，但做到需要勇气。&quot;——巴菲特</p></blockquote><p>本页收录1974年<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>年报中的经典语录，那一年美国市场深陷熊市，通胀失控，保险行业全面亏损。</p><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;在别人恐惧时贪婪。这是投资的最好时机。1974年市场情绪已经过度悲观，正是价值投资者应该关注的历史性时刻。&quot;</p></blockquote><blockquote><p>&quot;当整个市场都在恐慌时，持有没有杠杆、流动性充足的企业，是最理性的应对策略。&quot;</p></blockquote><blockquote><p>&quot;在过去的几年里，我们一直在评论保险业务超常的高承保利润率。这一现象最终必然引发非理性的行业竞争，进而导致费率不足。这是周期的必然，不是意外。&quot;</p></blockquote><blockquote><p>&quot;我们在保险投资中始终坚持一条原则：永远不要为了追求收益而牺牲流动性。当同行都在冒险时，我们选择保守；当潮水退去，我们手里还有资金可以买入打折资产。&quot;</p></blockquote><blockquote><p>&quot;1974年的教训是：风险来自于你不知道自己在做什么，不是波动本身。保持流动性、不使用过高杠杆，是防范风险的根本。&quot;</p></blockquote><blockquote><p>&quot;恐惧会传染，但理性不会。当市场一边倒地恐慌时，往往也是历史性机会显现的时刻。&quot;</p></blockquote><hr><h2 id="本年背景" tabindex="-1">本年背景 <a class="header-anchor" href="#本年背景" aria-label="Permalink to &quot;本年背景&quot;">​</a></h2><p>1974年，美国经济深陷滞胀泥潭：通胀高企、保险行业承保亏损、银行盈利下滑。伯克希尔当年净利润下降，但保险投资组合的流动性大幅提升。巴菲特在致股东信中写道：&quot;1975年的前景并不乐观……我们计划继续增强财务实力和流动性，为保险费率回归合理水平的时机做好准备。&quot;</p><hr><h2 id="深入阅读" tabindex="-1">深入阅读 <a class="header-anchor" href="#深入阅读" aria-label="Permalink to &quot;深入阅读&quot;">​</a></h2><p><a href="/search.html?q=→ 原文翻译">01_letters/1974年/翻译</a> · <a href="/search.html?q=→ 核心总结">01_letters/1974年/核心总结</a></p>',17)])])}const i=o(u,[["render",l]]);export{n as __pageData,i as default};
